function isPossibleToVisitAll(attractions, hotelCords, startTimeStr, closeTimeStr) {
    let startTimeMin = startTimeStr.split(":");
    startTimeMin = Number(startTimeMin[0]) * 60 + Number(startTimeMin[1]);
    let closeTimeMin = closeTimeStr.split(":");
    closeTimeMin = Number(closeTimeMin[0]) * 60 + Number(closeTimeMin[1]);
    let cords = hotelCords.split(",");
    let hotelX = Number(cords[0]);
    let hotelY = Number(cords[1]);
    let distance = 0;
    let currentX = hotelX;
    let currentY = hotelY;

    for (let i = 0; i < attractions.length; i++) {
        let dx = attractions[i].x - currentX;
        let dy = attractions[i].y - currentY;
        distance += Math.sqrt(dx * dx + dy * dy) * 12 + attractions[i].v;
        currentX = attractions[i].x;
        currentY = attractions[i].y;
    }

    let returnDx = currentX - hotelX;
    let returnDy = currentY - hotelY;
    distance += Math.sqrt(returnDx * returnDx + returnDy * returnDy) * 12;

    let totalTime = distance;
    let availableTime = closeTimeMin - startTimeMin;

    return totalTime <= availableTime;
}

