function epidemic(tm, n, s0, i0, b, a) {
    let dt = tm / n;
    let S = s0;
    let I = i0;
    let R = 0;
    let maxI = I;

    for (let i = 0; i < n; i++) {
        let newS = S - dt * b * S * I;
        let newI = I + dt * (b * S * I - a * I);
        let newR = R + dt * a * I;
        S = newS;
        I = newI;
        R = newR;
        if (I > maxI) {
            maxI = I;
        }
    }
    return Math.floor(maxI);
}

